we have mod(2) arithmetic: xor (for logical/boolean values)


% lights out puzzle by linear algebra
% one among several different aproaches
% it can be shortened by using specific matlab features (true,false)
% the sizes a wired in constants
% columnwise flattening used! matrix -&gt; matrix(:)
% in a mod(2) system the elimination is a simple xor() operation:
% aj=aj-1*ai is the only possible elimination operation and -1 is 1 (mod(2)).

clc; clear;

% initial state
% these are puzzles from the applet in the link
%
% puzzle 1
% S=zeros(5,5); 
% S(3,:)=[1,0,1,0,1]; 
% S=logical(S);
%
% puzzle 2
% S=zeros(5,5); 
% S([1,2,4,5],:)=repmat([1,0,1,0,1],4,1); 
% S=logical(S);
%
% puzzle 3
S=zeros(5,5); 
S([2,3,4],:)=repmat([1,1,0,1,1],3,1); 
S([1,5],:)=repmat([0,1,0,1,0],2,1); 
S=logical(S);


S
S=S(:);
% target state (zero here)
T=zeros(5,5); T=logical(T);
%T
T=T(:);

A=zeros(25,25); A=logical(A);

% the button vectors, that is the coefficient matrix
% the column-wise flattening is heavily used
for j=1:5
   for i=1:5
      k=i+(j-1)*5; % column-wise flattening
      % fprintf("%d %d %d\n",i,j,k);
      A(k,k)=1;
      % neighbours in the column
      if i&gt;1, A(k-1,k)=1;end
      if i&lt;5, A(k+1,k)=1;end
      % neighbours in the row
      if j&gt;1, A(k-5,k)=1;end
      if j&lt;5, A(k+5,k)=1;end
   end
end
A

% here comes the actual gaussian elimination
% for simplicity we'll also use backward elimination (Gauss-Jordan)
% this way no need to extract the solution separately

% extended matrix:
A=[A, xor(S,T)];
% forward elimination
for i=1:25
   nonzeros=find(A(i:end,i));
   if isempty(nonzeros)
      continue;
   else
      % relative index!!!
      k=nonzeros(1);
      if k&gt;1
         A([i,i+k-1],:)=A([i+k-1,i],:);
      end
   end
   for j=(i+1):25
      if A(j,i)
         A(j,:)=xor(A(j,:),A(i,:));
      end
   end
end
A
% backward elimination
for i=25:-1:1
   if not(A(i,i)), continue; end
   for j=(i-1):-1:1
      if A(j,i)
         A(j,:)=xor(A(j,:),A(i,:));
      end
   end
end

A

% transforming back the matrix and the right hand side
% the b became x
x=A(:,26);
A=A(1:25,:);

% final check (impossibility)
% full zero row in A but a non-zero in x (in the same row)
% the classical is always solvable, but one can set different flipping rules
% for the buttons...

% we apply here row-wise summation -&gt; look for the 2. parameter in sum call
if any(x&gt;sum(A,2))
   disp("we failed :-(");
   return;
end

% reshaping to get the human readable locations of the used buttons
reshape(x,5,5)

